import { UploadThingError } from 'uploadthing/server';
import { createUploadthing, type FileRouter } from 'uploadthing/next';
import { currentUser } from '@clerk/nextjs/server';
import { createDocument, updateDocumentStatus } from '@/lib/services/documents';
import { createSummary } from '@/lib/services/summaries';
import { summarizePdf } from '@/lib/services/ai';
import { toUserId, toTenantId } from '@/lib/types';

const f = createUploadthing();

export const ourFileRouter = {
  pdfUploader: f({ pdf: { maxFileSize: '32MB' } })
    .middleware(async () => {
      const user = await currentUser();
      if (!user) throw new UploadThingError('Unauthorized');
      return { userId: user.id };
    })
    .onUploadComplete(async ({ metadata, file }) => {
      const userId = toUserId(metadata.userId);
      const tenantId = toTenantId(metadata.userId);

      // 1. Create document record
      const doc = await createDocument(tenantId, {
        userId,
        storageUrl: file.url,
        storageKey: file.key,
        originalFilename: file.name,
        mimeType: file.type ?? 'application/pdf',
        sizeBytes: file.size,
      });

      // 2. Update status to PARSING
      await updateDocumentStatus(tenantId, doc.id, 'PARSING');

      // 3. Summarize the PDF with Gemini
      let shortSummary: string;
      let fullSummary: string;

      try {
        const result = await summarizePdf(file.url, file.name);
        shortSummary = result.shortSummary;
        fullSummary = result.fullSummary;
        await updateDocumentStatus(tenantId, doc.id, 'PARSED');
      } catch (error) {
        console.error('PDF summarization failed:', error);
        shortSummary = 'Summary generation failed. Please try re-uploading.';
        fullSummary = `An error occurred while processing this document: ${error instanceof Error ? error.message : 'Unknown error'}`;
        await updateDocumentStatus(tenantId, doc.id, 'FAILED');
      }

      // 4. Save the summary
      const summary = await createSummary(tenantId, {
        documentId: doc.id,
        title: file.name.replace(/\.pdf$/i, ''),
        shortSummary,
        fullSummary,
        createdBy: userId,
      });

      return {
        userId: metadata.userId,
        fileKey: file.key,
        fileUrl: file.url,
        summaryId: summary.id,
      };
    }),
} satisfies FileRouter;

export type OurFileRouter = typeof ourFileRouter;
